function findKthCharacter(s, k) {
    const n = s.length;
    let size = 0;

    for (const c of s) {
        if (/\d/.test(c)) {
            size = size * Number(c);
        } else {
            size++;
        }
    }

    for (let i = n - 1; i >= 0; i--) {
        const c = s.charAt(i);
        k %= size;
        if (k === 0 && !/\d/.test(c)) {
            return c;
        }

        if (/\d/.test(c)) {
            size /= Number(c);
        } else {
            size--;
        }
    }

    return '-';
}
