public char findKthCharacter(String s, int k) {
    int n = s.length();
    long size = 0;

    for (char c : s.toCharArray()) {
        if (Character.isDigit(c)) {
            size = size * (c - '0');
        } else {
            size++;
        }
    }

    for (int i = n - 1; i >= 0; i--) {
        char c = s.charAt(i);
        k %= size;
        if (k == 0 && !Character.isDigit(c)) {
            return c;
        }

        if (Character.isDigit(c)) {
            size /= (c - '0');
        } else {
            size--;
        }
    }

    return '-';
}
